import { ParsedLine, ProjectMap } from '../types';

// Regex to capture the structure: "KEY": "TEXT",
// Capturing groups:
// 1: Prefix (spaces + "key" + : + space + quote)
// 2: The Text content
// 3: Suffix (quote + optional comma + optional spaces)
const LINE_REGEX = /^(\s*".+?"\s*:\s*")(.*)("[,]??\s*)$/;

export const parseFileContent = (content: string, fileName: string): ProjectMap => {
  const rawLines = content.split(/\r?\n/);

  const parsedLines: ParsedLine[] = rawLines.map((line, index) => {
    const match = line.match(LINE_REGEX);

    if (match) {
      return {
        id: index,
        originalContent: line,
        isTranslatable: true,
        prefix: match[1],
        text: match[2],
        suffix: match[3],
      };
    } else {
      // Return non-translatable lines (comments, formatting, empty lines) as is
      return {
        id: index,
        originalContent: line,
        isTranslatable: false,
        prefix: line,
        text: '',
        suffix: '',
      };
    }
  });

  return {
    fileName,
    lines: parsedLines,
    timestamp: Date.now(),
  };
};

export const generateExportText = (projectMap: ProjectMap): string => {
  return projectMap.lines.map(line => {
    if (line.isTranslatable) {
      return line.text;
    } else {
      // Keep empty lines empty to maintain strict 1:1 line mapping
      // If it's a technical line (like a brace), we output empty string in the translation file
      // so the translator knows not to touch that line index.
      return ''; 
    }
  }).join('\n');
};

export const generateMergedFile = (projectMap: ProjectMap, translatedText: string): string => {
  const translatedLines = translatedText.split(/\r?\n/);

  // Warning if line counts mismatch, but attempt to merge anyway
  if (translatedLines.length !== projectMap.lines.length) {
    console.warn(`Line count mismatch! Map: ${projectMap.lines.length}, Translation: ${translatedLines.length}`);
  }

  return projectMap.lines.map((line, index) => {
    if (!line.isTranslatable) {
      return line.originalContent;
    }

    // Get the translated text for this specific line index
    // Fallback to original text if the translation file is too short or empty at that line
    const translatedLineContent = translatedLines[index] !== undefined ? translatedLines[index] : line.text;

    // If the translator left it strictly empty, we might want to decide if we keep original or empty.
    // For now, we trust the input. If they deleted it, it becomes empty string.
    return `${line.prefix}${translatedLineContent}${line.suffix}`;
  }).join('\n');
};

