  const mapFileInputRef = useRef<HTMLInputElement>(null);
  const translationInputRef = useRef<HTMLInputElement>(null);

  // Handlers
  const handleSourceUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      const map = parseFileContent(content, file.name);
      setProjectMap(map);
      setStep(2);
    };
    reader.readAsText(file);
  };

  const handleMapUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (json.lines && json.fileName) {
          setProjectMap(json as ProjectMap);
          setStep(2); // Jump to export/merge step
        } else {
          alert("Invalid Map JSON file.");
        }
      } catch (err) {
        alert("Error parsing JSON map.");
      }
    };
    reader.readAsText(file);
  };

  const handleTranslationUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      setTranslatedContent(content);
      if (projectMap) {
        const merged = generateMergedFile(projectMap, content);
        setFinalOutput(merged);
        setStep(3);
      }
    };
    reader.readAsText(file);
  };

  const downloadFile = (filename: string, content: string, type: string = 'text/plain') => {
    const blob = new Blob([content], { type });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleExportClean = () => {
    if (!projectMap) return;
    const text = generateExportText(projectMap);
    downloadFile(`${projectMap.fileName.replace(/\.[^/.]+$/, "")}_clean_lines.txt`, text);
  };

  const handleExportMap = () => {
    if (!projectMap) return;
    downloadFile(`${projectMap.fileName}.map.json`, JSON.stringify(projectMap, null, 2), 'application/json');
  };

  const handleDownloadFinal = () => {
    if (!finalOutput || !projectMap) return;
    downloadFile(`localized_${projectMap.fileName}`, finalOutput);
  };

  const reset = () => {
    setStep(1);
    setProjectMap(null);
    setTranslatedContent(null);
    setFinalOutput(null);
  };

  return (
    <div className="min-h-screen bg-enshrouded-900 text-enshrouded-text font-sans selection:bg-enshrouded-accent selection:text-white">
      {/* Header */}
      <header className="border-b border-enshrouded-700 bg-enshrouded-800 py-6">
        <div className="container mx-auto px-6 flex justify-between items-center">
          <div>
            <h1 className="text-2xl font-bold text-white tracking-wide">Enshrouded <span className="text-enshrouded-accent">Translator</span></h1>
            <p className="text-sm text-gray-400 mt-1">Split, Translate, and Merge Game Localization Files</p>
          </div>
          {step > 1 && (
             <Button variant="secondary" onClick={reset} icon={<RefreshIcon />}>
               Start Over
             </Button>
          )}
        </div>
      </header>

      {/* Main Content */}
      <main className="container mx-auto px-6 py-10 max-w-4xl space-y-8">

        {/* Step 1: Import */}
        <StepCard 
          title="Import Source File" 
          stepNumber={1} 
          isActive={step === 1} 
          isCompleted={step > 1}
        >
          <div className="space-y-6">
            <p className="text-gray-300">
