            </p>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {/* Option A: New Project */}
              <div className="border border-dashed border-enshrouded-600 rounded-lg p-8 text-center hover:border-enshrouded-accent transition-colors">
                <div className="mb-4 flex justify-center text-enshrouded-accent">
                  <FileIcon size={48} />
                </div>
