                <div className="mb-4 flex justify-center text-gray-500">
                   <CodeIcon size={48} />
                </div>
                <h4 className="text-lg font-medium text-white mb-2">Continue Project</h4>
                <p className="text-sm text-gray-500 mb-6">Upload .json map file</p>
                <input 
                  type="file" 
                  ref={mapFileInputRef} 
                  onChange={handleMapUpload} 
                  className="hidden" 
                  accept=".json"
                />
                <Button variant="secondary" onClick={() => mapFileInputRef.current?.click()}>
                  Load Map JSON
                </Button>
              </div>
            </div>
          </div>
        </StepCard>

        {/* Step 2: Extract & Translate */}
        <StepCard 
          title="Extract & Translate" 
          stepNumber={2} 
          isActive={step === 2} 
          isCompleted={step > 2}
        >
          <div className="space-y-8">
            <div className="flex flex-col md:flex-row gap-6">
              <div className="flex-1 space-y-4">
                <h4 className="text-white font-medium flex items-center">
