import { ParsedLine, ProjectMap } from '../types';

// Trigger: We start looking for a value when we see this property
const NAME_TRIGGER_REGEX = /"Name"\s*:\s*"DefaultText"/;

// Target: We capture the text when we see a "Value" property that is a string
// Captures: 
// 1: Prefix (spaces + "Value" + : + space + quote)
// 2: The Text content
// 3: Suffix (quote + optional comma + optional spaces)
const VALUE_CAPTURE_REGEX = /^(\s*"Value"\s*:\s*")(.*)("[,]??\s*)$/;

export const parseFileContent = (content: string, fileName: string): ProjectMap => {
  const rawLines = content.split(/\r?\n/);
  let waitingForValue = false;

  const parsedLines: ParsedLine[] = rawLines.map((line, index) => {
    // 1. Safety check: If we are waiting for a value but hit the end of an object, 
    // stop waiting to prevent bleeding into the next block.
    if (waitingForValue && line.trim().match(/^\},?$/)) {
      waitingForValue = false;
    }

    // 2. If we are inside a "DefaultText" object, check for the Value field
    if (waitingForValue) {
      const match = line.match(VALUE_CAPTURE_REGEX);

      if (match) {
        // We found the string value!
        waitingForValue = false; // Reset state

        const rawText = match[2];
        // Unescape escaped quotes for cleaner translation experience
        const cleanedText = rawText.replace(/\\"/g, '"');

        return {
          id: index,
          originalContent: line,
          isTranslatable: true,
          prefix: match[1],
          text: cleanedText,
          suffix: match[3],
        };
      }
    }

    // 3. Check if this line is the "DefaultText" identifier
    if (line.match(NAME_TRIGGER_REGEX)) {
      waitingForValue = true;
    }

    // Default: Return non-translatable lines (structure, keys, other values) as is
    return {
      id: index,
      originalContent: line,
      isTranslatable: false,
      prefix: line,
      text: '',
      suffix: '',
    };
  });

  return {
    fileName,
    lines: parsedLines,
    timestamp: Date.now(),
  };
};

export const generateExportText = (projectMap: ProjectMap): string => {
  // Filter out non-translatable lines completely to avoid empty lines in the text file
  return projectMap.lines
    .filter(line => line.isTranslatable)
    .map(line => line.text)
    .join('\n');
};

export const generateMergedFile = (projectMap: ProjectMap, translatedText: string): string => {
  const translatedLines = translatedText.split(/\r?\n/);
  let translationIndex = 0;

  // Debug log to check counts
  const expectedCount = projectMap.lines.filter(l => l.isTranslatable).length;
  console.log(`Merging: Expected ${expectedCount} lines, got ${translatedLines.length} in translation file.`);

  return projectMap.lines.map((line) => {
    if (!line.isTranslatable) {
      return line.originalContent;
    }

    // Get the next available translated line from the list
    let translatedLineContent = line.text; // Fallback to original

    if (translationIndex < translatedLines.length) {
      translatedLineContent = translatedLines[translationIndex];
      translationIndex++;
    }

    // Escape quotes back to \" to prevent JSON corruption
    const escapedContent = translatedLineContent.replace(/"/g, '\\"');

    return `${line.prefix}${escapedContent}${line.suffix}`;
  }).join('\n');
};

