import { ParsedLine, ProjectMap } from '../types';

// Trigger: We look for this specific property line indicating a property that might have a value
const EXTENSION_TRIGGER_REGEX = /"PropertyTagExtensions"\s*:\s*"NoExtension"/;

// Target: We capture the text when we see a "Value" property that is a string
// Captures: 
// 1: Prefix (spaces + "Value" + : + space + quote)
// 2: The Text content
// 3: Suffix (quote + optional comma + optional spaces)
const VALUE_CAPTURE_REGEX = /^(\s*"Value"\s*:\s*")(.*)("[,]??\s*)$/;

// Helper regex to detect a "Value" line that is NOT a string (e.g. null, number, array, boolean)
// used to stop waiting if we encounter a non-translatable value.
const VALUE_NON_STRING_REGEX = /"Value"\s*:/;

export const parseFileContent = (content: string, fileName: string): ProjectMap => {
  const rawLines = content.split(/\r?\n/);
  let waitingForValue = false;

  const parsedLines: ParsedLine[] = rawLines.map((line, index) => {
    // 1. Safety check: If we are waiting for a value but hit the end of an object, 
    // stop waiting to prevent bleeding into the next block.
    if (waitingForValue && line.trim().match(/^\},?$/)) {
      waitingForValue = false;
    }

    // 2. If we are waiting for the Value field (triggered by PropertyTagExtensions)
    if (waitingForValue) {
      const match = line.match(VALUE_CAPTURE_REGEX);

      if (match) {
        const rawText = match[2];

        // NEW CHECK: Ignore system paths starting with 'conversations/'
        if (rawText.startsWith('conversations/')) {
          waitingForValue = false;
          return {
             id: index,
             originalContent: line,
             isTranslatable: false,
             prefix: line,
             text: '',
             suffix: '',
          };
        }

        // We found a valid string value! This is translatable.
        waitingForValue = false; // Reset state

        // Unescape escaped quotes for cleaner translation experience
        const cleanedText = rawText.replace(/\\"/g, '"');

        return {
          id: index,
          originalContent: line,
          isTranslatable: true,
          prefix: match[1],
          text: cleanedText,
          suffix: match[3],
        };
      } else if (line.match(VALUE_NON_STRING_REGEX)) {
        // We found a "Value" line, but it didn't match the string capture regex.
        // This means it's likely null, a number, or an array/struct. 
        // We stop waiting and treat this line as non-translatable.
        waitingForValue = false;
      }
    }

    // 3. Check if this line is the trigger for the next value
    if (line.match(EXTENSION_TRIGGER_REGEX)) {
      waitingForValue = true;
    }

    // Default: Return non-translatable lines
    return {
      id: index,
      originalContent: line,
      isTranslatable: false,
      prefix: line,
      text: '',
      suffix: '',
    };
  });

  return {
    fileName,
    lines: parsedLines,
    timestamp: Date.now(),
  };
};

