import { ParsedLine, ProjectMap } from '../types';

// New Logic: Detect pairs of strings in JSON arrays.
// The first string is the Key (ends with comma).
// The second string is the Value (no comma, target for translation).

// Regex to detect the first string (Key)
// Matches: whitespace "text" whitespace comma whitespace
const KEY_REGEX = /^\s*"(?:[^"\\]|\\.)*"\s*,\s*$/;

// Regex to detect the second string (Value)
// Matches: whitespace "text" whitespace (no comma)
// Capture 1: Prefix (spaces + ")
// Capture 2: Content
// Capture 3: Suffix (" + spaces)
const VALUE_REGEX = /^(\s*")((?:[^"\\]|\\.)*)("\s*)$/;

export const parseFileContent = (content: string, fileName: string): ProjectMap => {
  const rawLines = content.split(/\r?\n/);
  let waitingForValue = false;

  const parsedLines: ParsedLine[] = rawLines.map((line, index) => {

    // If we encountered a Key line previously, we expect a Value line now
    if (waitingForValue) {
      const match = line.match(VALUE_REGEX);

      if (match) {
        const rawText = match[2];

        // Filter: Ignore system paths starting with 'conversations/'
        if (rawText.startsWith('conversations/')) {
          waitingForValue = false;
          return {
             id: index,
             originalContent: line,
             isTranslatable: false,
             prefix: line,
             text: '',
             suffix: '',
           };
        }

        // We found a valid value!
        waitingForValue = false; 

        // Unescape escaped quotes for cleaner translation experience
        const cleanedText = rawText.replace(/\\"/g, '"');

        return {
          id: index,
          originalContent: line,
          isTranslatable: true,
          prefix: match[1],
          text: cleanedText,
          suffix: match[3],
        };
      } else {
        // Line didn't match Value format (e.g. might be another key, or array end)
        // Stop waiting to avoid incorrect mapping
        waitingForValue = false;
      }
    }

    // Check if this line is a Key (String followed by comma)
    if (line.match(KEY_REGEX)) {
      waitingForValue = true;
    }

    // Default: Non-translatable
    return {
      id: index,
      originalContent: line,
      isTranslatable: false,
      prefix: line,
      text: '',
      suffix: '',
    };
  });

  return {
    fileName,
    lines: parsedLines,
    timestamp: Date.now(),
  };
};

