// Logic for Core Keeper localization file
// Pattern: 
// ID [TAB] Type(Text) [TAB] [TAB] Value [Trailing TABS?]
// Example: Achievements/CatchStarlightNautilus	Text		Legendary Fossil	

// Regex Breakdown:
// 1. ^(.*\tText\t\t)  -> Prefix: Captures ID, "Text" type, and the separator tabs.
// 2. (.*?)            -> Text: Captures the actual text (non-greedy).
// 3. (\t*)?$          -> Suffix: Captures any trailing tabs at the end of the line.
const CORE_KEEPER_REGEX = /^(.*\tText\t\t)(.*?)(\t*)?$/;

export const parseFileContent = (content: string, fileName: string): ProjectMap => {
