    const match = line.match(CORE_KEEPER_REGEX);

    if (match) {
      return {
        id: index,
        originalContent: line,
        isTranslatable: true,
        prefix: match[1],         // e.g. "Achievements/CatchStarlightNautilus\tText\t\t"
        text: match[2],           // e.g. "Legendary Fossil"
        suffix: match[3] || '',   // Trailing tabs if present
