          isActive={step === 1} 
          isCompleted={step > 1}
        >
          <div className="space-y-6">
            <p className="text-gray-300">
              Upload the original game file (<code className="bg-enshrouded-900 px-1 py-0.5 rounded text-enshrouded-accent">.csv</code>). 
