                  accept=".json"
                />
                <Button variant="secondary" onClick={() => mapFileInputRef.current?.click()}>
                  Load Map JSON
                </Button>
              </div>
            </div>
          </div>
        </StepCard>

        {/* Step 2: Extract & Translate */}
        <StepCard 
          title="Extract & Translate" 
          stepNumber={2} 
          isActive={step === 2} 
          isCompleted={step > 2}
        >
          <div className="space-y-8">
            <div className="flex flex-col md:flex-row gap-6">
              <div className="flex-1 space-y-4">
                <h4 className="text-white font-medium flex items-center">
                  <span className="w-6 h-6 rounded-full bg-enshrouded-700 text-xs flex items-center justify-center mr-2">A</span>
                  Download Workspace
                </h4>
                <p className="text-sm text-gray-400">
                  1. Download the <strong className="text-white">Clean Text</strong> file (TXT).<br/>
                  2. Download the <strong className="text-white">Map JSON</strong>. Keep this safe!
                </p>
                <div className="flex gap-3 pt-2">
                  <Button onClick={handleExportClean} icon={<DownloadIcon />}>
                    Clean Text (.txt)
                  </Button>
                  <Button variant="secondary" onClick={handleExportMap} icon={<CodeIcon />}>
                    Map (.json)
                  </Button>
                </div>
              </div>

              <div className="flex-1 space-y-4 border-l border-enshrouded-700 pl-0 md:pl-6">
                <h4 className="text-white font-medium flex items-center">
                  <span className="w-6 h-6 rounded-full bg-enshrouded-700 text-xs flex items-center justify-center mr-2">B</span>
                  Upload Translation
                </h4>
                <p className="text-sm text-gray-400">
                  Upload the translated TXT file. The line count must match the original.
                </p>
                <div className="pt-2">
                  <input 
                    type="file" 
                    ref={translationInputRef} 
                    onChange={handleTranslationUpload} 
                    className="hidden" 
                    accept=".txt"
                  />
                  <Button onClick={() => translationInputRef.current?.click()} icon={<UploadIcon />}>
                    Upload Translated Text
                  </Button>
                </div>
              </div>
            </div>

            {/* Preview Area */}
            {projectMap && (
              <div className="bg-enshrouded-900 rounded-lg border border-enshrouded-700 p-4">
                <h5 className="text-xs uppercase text-gray-500 font-bold mb-2 tracking-wider">Source Analysis Preview</h5>
                <div className="font-mono text-sm space-y-1 h-48 overflow-y-auto">
                  {projectMap.lines.slice(0, 10).map((line) => (
                    <div key={line.id} className="flex">
                      <span className="text-gray-600 w-12 text-right mr-4 select-none">{line.id + 1}</span>
                      {line.isTranslatable ? (
                        <span className="text-green-400 truncate">
                          <span className="text-gray-500 opacity-50">{line.prefix.replace(/\t/g, '→')}</span>
                          <span className="bg-green-900/30 text-green-300 px-1 rounded">{line.text}</span>
                          <span className="text-gray-500 opacity-50">{line.suffix.replace(/\t/g, '→')}</span>
                        </span>
                      ) : (
                        <span className="text-gray-600 italic truncate">{line.originalContent}</span>
                      )}
                    </div>
                  ))}
                  <div className="text-gray-600 text-center italic mt-2">... {projectMap.lines.length} lines total ...</div>
                </div>
              </div>
            )}
          </div>
        </StepCard>

        {/* Step 3: Finish */}
        <StepCard 
          title="Final Result" 
          stepNumber={3} 
          isActive={step === 3} 
          isCompleted={false}
        >
          <div className="space-y-6">
             <div className="bg-green-900/20 border border-green-800 rounded-lg p-4 flex items-start">
                <div className="text-green-500 mt-1 mr-3"><CheckIcon /></div>
                <div>
                  <h4 className="text-white font-medium">Merge Successful!</h4>
                  <p className="text-sm text-gray-400 mt-1">
                    Your translated text has been successfully injected back into the original CSV structure.
                  </p>
                </div>
             </div>

             {/* Diff View / Preview */}
             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="bg-enshrouded-900 rounded border border-enshrouded-700 p-3">
                   <div className="text-xs text-gray-500 mb-2 uppercase">Original (Preview)</div>
                   <pre className="text-xs font-mono text-gray-400 overflow-x-auto whitespace-pre">
                     {projectMap?.lines.slice(0, 5).map(l => l.originalContent).join('\n')}
                     {'\n...'}
                   </pre>
                </div>
                <div className="bg-enshrouded-900 rounded border border-enshrouded-accent p-3">
                   <div className="text-xs text-enshrouded-accent mb-2 uppercase">Merged Result (Preview)</div>
                   <pre className="text-xs font-mono text-gray-300 overflow-x-auto whitespace-pre">
                     {finalOutput?.split('\n').slice(0, 5).join('\n')}
                     {'\n...'}
                   </pre>
                </div>
             </div>

             <div className="flex justify-end pt-4">
                <Button onClick={handleDownloadFinal} icon={<DownloadIcon />}>
                  Download Final CSV
                </Button>
             </div>
          </div>
        </StepCard>

      </main>
    </div>
  );
};

export default App;

